import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import ProtectedRoute from './components/ProtectedRoute';
import Header from './components/Header';
import Sidebar from './components/Sidebar';
import BottomNavBar from './components/BottomNavBar';
import LayoutInterno from './components/LayoutInterno';
// ... outas importações e estilos

function App() {
  const [active, setActive] = useState('dashboard');
  const { onlineUsers } = useAuth();

  const renderConteudo = () => {
    // lógica de renderização de páginas
  };

  return (
    <AuthProvider>
      <Router>
        <Header onlineUsers={onlineUsers} />
        <div className="bg-[#F2F4F7] min-h-screen">
          <div className="flex flex-col-reverse md:flex-row">
            <main
              className="
                flex-1
                order-1 md:order-none
                ml-0 md:ml-64
                mt-16 p-4
                h-[calc(100vh-64px)] overflow-y-auto
              "
            >
              <div className="mx-auto">
                {renderConteudo()}
              </div>
            </main>
            <Sidebar active={active} onMenuClick={setActive} />
          </div>
        </div>
        <BottomNavBar active={active} onMenuClick={setActive} />
        <Routes>
          <Route
            path="/*"
            element={
              <ProtectedRoute>
                <LayoutInterno />
              </ProtectedRoute>
            }
          />
          <Route path="*" element={<Navigate to="/login" replace />} />
        </Routes>
      </Router>
    </AuthProvider>
  );
}

export default App;
